@js:
var html = result;
var aidMatch = html.match(/var READ_AID\s*=\s*(\d+)/);
var cidMatch = html.match(/var READ_CID\s*=\s*(\d+)/);
var bucketMatch = html.match(/var READ_BUCKET\s*=\s*(\d+)/);
var signMatch = html.match(/var READ_SIGN\s*=\s*['"]([^'"]+)['"]/);
if (!aidMatch || !cidMatch || !bucketMatch || !signMatch) {
  return '参数提取失败';
}
var aid = aidMatch[1];
var cid = cidMatch[1];
var bucket = bucketMatch[1];
var sign = signMatch[1];
var ts = new Date().getTime();
var sourceUrl = source.getKey();
var apiUrl = sourceUrl + '/book/' + aid + '/' + cid + '.html?ajax=1&aid=' + aid + '&cid=' + cid + '&bk=' + bucket + '&sign=' + sign + '&_=' + ts;
var contentHtml = java.ajax(apiUrl);
contentHtml
